import{_ as s,o as t,c as r,ag as a}from"./chunks/framework.ETe_P6d1.js";const e="/kaiping-reports/assets/1.Bp5ma8nA.jpg",i="/kaiping-reports/assets/2.D2nT86DN.jpg",o="/kaiping-reports/assets/3.CZMI-b-9.jpg",_="/kaiping-reports/assets/4.19bgN3V1.jpg",n="/kaiping-reports/assets/5.ClfWzLEs.jpg",c="/kaiping-reports/assets/6.DR_O3Mrz.jpg",g="/kaiping-reports/assets/7.DCdgAite.jpg",m="/kaiping-reports/assets/8.B4DlyllN.jpg",l="/kaiping-reports/assets/9.oWqfg9J6.jpg",d="/kaiping-reports/assets/10.DjPBtHlS.jpg",N=JSON.parse('{"title":"开平地区传统建筑的建造逻辑、文化表达与当代转译——以立园、仓东村与赤坎古镇为例的调研报告","description":"","frontmatter":{"title":"开平地区传统建筑的建造逻辑、文化表达与当代转译——以立园、仓东村与赤坎古镇为例的调研报告"},"headers":[],"relativePath":"reports/符贝莹/符贝莹_调研报告.md","filePath":"reports/符贝莹/符贝莹_调研报告.md"}'),k={name:"reports/符贝莹/符贝莹_调研报告.md"};function f(j,p,D,h,u,T){return t(),r("div",null,[...p[0]||(p[0]=[a('<h1 id="开平地区传统建筑的建造逻辑、文化表达与当代转译——以立园、仓东村与赤坎古镇为例的调研报告" tabindex="-1">开平地区传统建筑的建造逻辑、文化表达与当代转译——以立园、仓东村与赤坎古镇为例的调研报告 <a class="header-anchor" href="#开平地区传统建筑的建造逻辑、文化表达与当代转译——以立园、仓东村与赤坎古镇为例的调研报告" aria-label="Permalink to &quot;开平地区传统建筑的建造逻辑、文化表达与当代转译——以立园、仓东村与赤坎古镇为例的调研报告&quot;">​</a></h1><p>——以立园、仓东村与赤坎古镇为例的调研报告</p><p>开平地区作为中国著名侨乡，其建筑形态在中国传统地域建筑体系中呈现出鲜明的特殊性。一方面，本土乡村社会长期形成的宗族结构、生活方式与自然环境塑造了稳定的建造体系；另一方面，近代以来华侨群体的经济回流与文化输入，又不断冲击并重塑这一体系，使得开平建筑在材料、结构及形式语言上呈现出显著的跨文化特征。以碉楼与骑楼为代表的建筑类型，更因其独特的历史价值与文化内涵，被纳入世界文化遗产体系之中。</p><p>本次调研选取立园、仓东村以及赤坎古镇为主要研究对象，尝试从“建造逻辑—文化表达—当代转译”的连续视角出发，探讨开平地区建筑如何在不同历史阶段中不断生成意义，并在当代文旅语境下获得新的存在方式。相较于将材料、装饰与利用割裂为独立维度，本文更关注三者之间的内在关联，即建筑如何从物质建构出发，逐步承载文化符号，并最终在现代社会中被重新诠释与再生产。</p><p>建筑首先是一种物质实践，其材料选择与构造方式不仅受制于技术条件与自然环境，同时也深刻反映了社会结构与文化取向。在开平地区，这种关系在乡村聚落与华侨庄园之间呈现出鲜明对比。</p><p>在仓东村中，传统建筑多采用青砖、夯土与木构体系，整体呈现出明显的在地性特征。从空间结构来看，碉楼并非孤立存在，而是与村落整体形成协同的防御体系。相关研究表明，开平地区碉楼与聚落之间构成“防御功能单元”，呈现出以多点集聚和联防为特征的空间格局。这一体系反映出当时社会环境中普遍存在的安全需求，也体现了宗族社会通过空间组织实现集体防御的策略。因此，仓东村的建造逻辑不仅是材料与结构的选择，更是社会关系与生存机制的空间化表达。</p><p><img src="'+e+'" alt="图1"></p><p>相比之下，立园则呈现出截然不同的建造逻辑和文化开放性。研究指出，开平地区建筑在20世纪初已成为西方建筑艺术在中国的重要展示载体，其空间布局与形式语言体现出显著的中西融合特征。立园作为华侨私人园林，其大量采用钢筋混凝土结构，并结合西式建筑语汇，如拱券、柱式与几何构图等。这些技术与形式显然超越了本地传统建造经验，反映出海外文化与工业技术的输入。与此同时，立园的空间布局强调景观性与观赏性，通过水体、亭台与路径的组织，构建出一种具有叙事性的园林空间。由此可见，其建造已不再仅仅满足功能需求，而是成为一种体现财富、身份与审美趣味的综合性表达。</p><p><img src="'+i+'" alt="图2"></p><p>因此，从仓东村到立园，可以看到开平建筑在建造层面上的一种转变：由以在地材料与防御功能为主导的“生存型建造”，逐步过渡为融合外来技术与审美的“表达型建造”。这一转变的背后，是不同社会群体在资源获取能力与文化认同上的差异。</p><p>如果说材料与构造构成了建筑的物质基础，那么装饰则是在这一基础上生成的文化表达。装饰并非孤立存在，而是依附于结构体系，并通过符号化的方式传递社会意义。</p><p>在仓东村中，建筑装饰多表现为灰塑、砖雕以及祠堂立面中的图案与构件。这些装饰内容往往与宗族文化密切相关，如姓氏标识、吉祥纹样及历史故事等，其功能在于强化集体认同与伦理秩序。祠堂作为聚落的精神中心，其装饰不仅具有审美价值，更承担着凝聚族群记忆与维系社会结构的作用。换言之，这类装饰的核心指向是“共同体”，其意义在于维持一种稳定的社会关系网络。</p><p><img src="'+o+'" alt="图3"></p><p>而在立园中，装饰语言则呈现出明显的异质性。罗马柱、拱券、浮雕以及西式栏杆等元素的运用，使建筑表面具有强烈的视觉冲击力。这些符号往往并不直接服务于功能，而更多用于表达主人身份、财富与海外经历。从文化层面来看，这是一种具有“展示性”的装饰体系，其核心不再是集体认同，而是个体成就的彰显。通过对西方建筑语汇的引入与再组合，立园形成了一种中西混合的审美风格，体现出华侨文化中“跨地域经验”的视觉化表达。</p><p><img src="'+_+'" alt="图4"></p><p><img src="'+n+'" alt="图5"></p><p>由此可以发现，尽管仓东村与立园都拥有丰富的装饰元素，但其文化指向却存在本质差异：前者强调血缘与集体，后者突出个体与流动性。这种差异不仅体现在形式上，更反映了不同社会结构下价值体系的转变。</p><p><img src="'+c+'" alt="图6"></p><p>随着社会结构的变化，传统建筑所依附的原有生活方式逐渐瓦解。然而，这并不意味着其文化意义的消失。相反，这些意义在当代语境中被重新解读，并转化为新的空间价值。赤坎古镇正是这一过程的典型案例。</p><p>赤坎古镇以骑楼街区为主要空间形态，其建筑本身已具备中西融合的历史特征。在当代开发过程中，该区域通过系统性的更新与改造，被塑造为一个高度商业化的文旅空间。其中，“做旧”策略成为最为关键的手段之一。通过对建筑表面肌理、色彩与细部构件的处理，设计者试图在视觉上重建一种“历史感”，使游客能够在短时间内获得对过去的感性认知。这种方法在一定程度上提升了空间的整体氛围，也增强了其吸引力。</p><p><img src="'+g+'" alt="图7"></p><p>与此同时，赤坎古镇通过多种方式将文化内容转化为可体验的产品。例如，以地方历史为主题的沉浸式舞台演出，使抽象的历史叙事被具象化呈现；特色酒店的植入，则将传统空间转化为可居住的消费场所；而以陈皮为代表的地方特产，如陈皮雪糕等，则进一步将地域文化转化为可携带、可消费的商品。这一系列操作共同构成了一种“文化体验系统”，使建筑不再仅仅是被观看的对象，而成为被参与与消费的媒介。</p><p><img src="'+m+'" alt="图8"></p><p>然而，这种转译过程也不可避免地带来新的问题。当历史被转化为表演与商品时，其真实性与复杂性往往被简化甚至重构。建筑不再承载真实的生活，而成为一种“被设计的过去”。因此，在肯定赤坎古镇成功激活空间活力的同时，也需要对其所呈现的历史真实性保持一定的反思。</p><p><img src="'+l+'" alt="图9"></p><p>通过对仓东村、立园与赤坎古镇的比较分析，可以看到开平地区建筑在不同阶段中所经历的连续转变。从最初以在地材料与防御需求为基础的建造实践，到依附其上的装饰符号所承载的文化表达，再到当代文旅语境中对这些意义的再利用与再生产，建筑始终处于一个不断生成与转译的过程中。</p><p>这一过程表明，开平建筑并非单一传统的延续，而是在华侨文化背景下形成的一种具有高度“混杂性”的体系。其材料与结构体现了技术与资源的流动，装饰符号记录了身份与价值的变迁，而在当代开发中，这些元素又被重新编码，转化为可被体验与消费的文化资源。</p><p>因此，开平地区建筑不仅是物质空间的建构，更是社会关系、文化认同与历史变迁的综合体现。从防御体系到装饰表达，再到当代文旅转译，其演化过程正如相关研究所揭示的，是一个由功能需求、文化输入与社会变迁共同驱动的动态过程。</p><p><img src="'+d+'" alt="图10"></p><p>[1] 梁雄飞, 阴劼, 杨彬, 宋铮. 开平碉楼与村落防御功能格局的时空演变[J]. 地理研究, 2017.<br> [2] 肖波. 历史的停留——浅析开平碉楼设计布局特色[J]. 兰台世界, 2015.<br> [3] 刘典财. 开平碉楼建筑装饰艺术特色研究[J]. 工业设计, 2019.</p>',30)])])}const P=s(k,[["render",f]]);export{N as __pageData,P as default};
